module traffic_light(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
parameter idle = 2'b00;
parameter s1_red = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green = 2'b11;
reg [1:0] state, next_state;
reg [7:0] cnt;
reg p_red, p_yellow, p_green;
always @(*) begin
    case (state)
        idle: begin
            next_state = s1_red;
        end
        s1_red: begin
            if (cnt == 3) next_state = s3_green;
            else next_state = s1_red;
        end
        s2_yellow: begin
            if (cnt == 3) next_state = s1_red;
            else next_state = s2_yellow;
        end
        s3_green: begin
            if (cnt == 3) next_state = s2_yellow;
            else next_state = s3_green;
        end
        default: next_state = idle;
    endcase
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 10;
        state <= idle;
    end else begin
        state <= next_state;
        if (state == s3_green) begin
            if (cnt == 3) cnt <= 10;
            else cnt <= cnt - 1;
        end else if (state == s2_yellow) begin
            if (cnt == 3) cnt <= 60;
            else cnt <= cnt - 1;
        end else if (state == s1_red) begin
            if (cnt == 3) cnt <= 10;
            else cnt <= cnt - 1;
        end else begin
            cnt <= cnt;
        end
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        p_red <= 0;
        p_yellow <= 0;
        p_green <= 0;
    end else begin
        p_red <= red;
        p_yellow <= yellow;
        p_green <= green;
    end
end
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        red <= 0;
        yellow <= 0;
        green <= 0;
    end else begin
        red <= p_red;
        yellow <= p_yellow;
        green <= p_green;
    end
end
assign clock = cnt;
endmodule
